        troubleshooting: "\u0623\u0635\u0644\u062d \u0627\u0644\u0645\u0634\u0643\u0644\u0627\u062a \u0627\u0644\u0634\u0627\u0626\u0639\u0629\u060c \u0648\u0627\u0641\u0647\u0645 \u0631\u0633\u0627\u0626\u0644 \u0627\u0644\u062e\u0637\u0623\u060c \u0648\u0623\u0639\u062f \u0648\u0643\u0644\u0627\u0621\u0643 \u0625\u0644\u0649 \u0627\u0644\u0645\u0633\u0627\u0631 \u0627\u0644\u0635\u062d\u064a\u062d."
