      "multi-provider": {
        headline: "\u063a\u064a\u0631 \u0645\u0642\u064a\u0651\u062f \u0628\u0645\u0632\u0648\u0651\u062f \u0630\u0643\u0627\u0621 \u0627\u0635\u0637\u0646\u0627\u0639\u064a \u0648\u0627\u062d\u062f",
        description: "\u0627\u0633\u062a\u062e\u062f\u0645 Claude \u0623\u0648 OpenAI \u0623\u0648 Gemini\u060c \u0623\u0648 \u0634\u063a\u0651\u0644 \u0627\u0644\u0646\u0645\u0627\u0630\u062c \u0645\u062d\u0644\u064a\u064b\u0627 \u0628\u0627\u0633\u062a\u062e\u062f\u0627\u0645 Ollama. \u062a\u0646\u0642\u0651\u0644 \u0628\u064a\u0646 \u0627\u0644\u0645\u0632\u0648\u0651\u062f\u064a\u0646 \u0628\u062d\u0631\u064a\u0629\u060c \u0648\u062e\u0635\u0651\u0635 \u0646\u0645\u0627\u0630\u062c \u0645\u062e\u062a\u0644\u0641\u0629 \u0644\u0648\u0643\u0644\u0627\u0621 \u0645\u062e\u062a\u0644\u0641\u064a\u0646\u060c \u0648\u0625\u0630\u0627 \u062a\u0639\u0637\u0651\u0644 \u0623\u062d\u062f \u0627\u0644\u0645\u0632\u0648\u0651\u062f\u064a\u0646 \u2014 \u064a\u062a\u062d\u0648\u0651\u0644 \u0648\u0643\u0644\u0627\u0624\u0643 \u062a\u0644\u0642\u0627\u0626\u064a\u064b\u0627 \u0625\u0644\u0649 \u0645\u0632\u0648\u0651\u062f \u0622\u062e\u0631.",
        cta: "\u0627\u062e\u062a\u0631 \u0630\u0643\u0627\u0621\u0643 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a"
      },
      genome: {
        headline: "\u064a\u0635\u0628\u062d \u0648\u0643\u0644\u0627\u0624\u0643 \u0623\u0643\u062b\u0631 \u0630\u0643\u0627\u0621\u064b \u062a\u0644\u0642\u0627\u0626\u064a\u064b\u0627",
        description: "\u0628\u062f\u0644\u0627\u064b \u0645\u0646 \u062a\u0639\u062f\u064a\u0644 \u0627\u0644\u062a\u0648\u062c\u064a\u0647\u0627\u062a \u064a\u062f\u0648\u064a\u064b\u0627 \u0644\u0633\u0627\u0639\u0627\u062a\u060c \u062f\u0639 \u0646\u0638\u0627\u0645 \u0627\u0644\u062c\u064a\u0646\u0648\u0645 \u064a\u062a\u0648\u0644\u0649 \u0630\u0644\u0643 \u0639\u0646\u0643. \u0641\u0647\u0648 \u064a\u062e\u062a\u0628\u0631 \u0627\u0644\u0627\u062e\u062a\u0644\u0627\u0641\u0627\u062a\u060c \u0648\u064a\u062d\u062a\u0641\u0638 \u0628\u0645\u0627 \u064a\u0646\u062c\u062d\u060c \u0648\u064a\u062a\u062e\u0644\u0651\u0635 \u0645\u0646 \u0627\u0644\u0628\u0627\u0642\u064a \u2014 \u062a\u0645\u0627\u0645\u064b\u0627 \u0643\u0627\u0644\u0627\u0646\u062a\u0642\u0627\u0621 \u0627\u0644\u0637\u0628\u064a\u0639\u064a \u0644\u0648\u0643\u0644\u0627\u0621 \u0627\u0644\u0630\u0643\u0627\u0621 \u0627\u0644\u0627\u0635\u0637\u0646\u0627\u0639\u064a \u0644\u062f\u064a\u0643.",
        cta: "\u0637\u0648\u0651\u0631 \u0648\u0643\u0644\u0627\u0621\u0643"
      }
